def inv1(i, N, isPresent, min, max, len):
	MIN = -129
	MAX = 128
	i_bounds = And(i >= 0, i <= N)
	len_is_i = (len == i)
	is_present_logic = (isPresent == If(i == 0, 0, 1))
	min_logic = (min == If(i == 0, MAX, 0))
	max_logic = (max == If(i == 0, MIN, i - 1))
	return And(i_bounds, len_is_i, is_present_logic, min_logic, max_logic)

def insert(v, isPresent, min, max, len, isPresent1, min1, max1, len1):
	len_update = (len1 == len + 1)
	is_present_update = (isPresent1 == 1)
	min_update = (min1 == If(len == 0, v, If(v < min, v, min)))
	max_update = (max1 == If(len == 0, v, If(v > max, v, max)))
	return And(len_update, is_present_update, min_update, max_update)

def remove(k, min, max, len, min1, max1, len1, ret1):
	precondition = And(len > 0, min <= k, k <= max)
	on_success = And(len1 == len - 1, ret1 == 1)
	on_failure = And(len1 == len, min1 == min, max1 == max, ret1 == 0)
	return If(precondition, on_success, on_failure)
